    processedIds: Object.freeze(processedIdsValue.filter((entry) => typeof entry === "string")),
    mailbox: Object.freeze(mailboxValue.map((entry) => $claspWorkflowNormalizeMessage(entry))),
    deadlineAt: $claspWorkflowNormalizeDeadline(objectValue.deadlineAt, `${workflowName}.run.deadlineAt`),
    cancelled: objectValue.cancelled === true,
    cancelReason: typeof objectValue.cancelReason === "string" && objectValue.cancelReason !== "" ? objectValue.cancelReason : null,
    retryPolicy: $claspWorkflowNormalizeRetryPolicy(objectValue.retryPolicy, workflowName),
    supervision: $claspWorkflowNormalizeSupervision(workflowName, objectValue.supervision),
    auditLog: Object.freeze((Array.isArray(objectValue.auditLog) ? objectValue.auditLog : []).map((entry) => $claspSnapshotValue(entry)))
